 3	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Button, StackItem } from '@patternfly/react-core';
 6	import { ExternalLinkSquareAltIcon } from '@patternfly/react-icons';
 7	
 8	const DynamicSSHKeyInjectionDescription = ({ isDynamicSSHInjectionEnabled }) => {
 9	  const { t } = useKubevirtTranslation();
10	
11	  if (isDynamicSSHInjectionEnabled) return <>{t('Store the key in a project secret.')}</>;
12	
13	  return (
14	    <StackItem className="text-muted">
15	      {t('Dynamic SSH key injection is not enabled in this virtual machine.')}{' '}
16	      <Button
17	        component="a"
18	        href={documentationURL.DYNAMIC_SSH_KEY_INJECTION}
19	        icon={<ExternalLinkSquareAltIcon />}
20	        iconPosition="right"
21	        isInline
22	        rel="noopener noreferrer"
23	        size="sm"
24	        target="_blank"
25	        variant="link"
26	      >
27	        {t('Learn more')}
28	      </Button>
29	    </StackItem>
30	  );
31	};
32	export default DynamicSSHKeyInjectionDescription;

